import React, { useState, useEffect } from "react";
import { BrowserRouter as Router, Routes, Route, Link, useNavigate } from "react-router-dom";
import Register from './Register';
import Home from "./Home";
import About from "./About";
import Login from "./Login";
import Profile from "./Profile";

import AdminLogin from "./admin/AdminLogin";
import AdminDashboard from "./admin/AdminDashboard";
import AdminProfile from "./admin/AdminProfile";
import ManageAdmins from "./admin/ManageAdmins";  // NEW IMPORT
import ProtectedRoute from "./admin/ProtectedRoute";

function App() {
  return (
    <Router>
      <OAuthCallback />
      <Navbar />
      <Routes>
        <Route path="/" element={<Home />} />
        <Route path="/about" element={<About />} />
        <Route path="/login" element={<Login />} />
        <Route path="/register" element={<Register />} />
        <Route path="/profile" element={<Profile />} />

        {/* ADMIN ROUTES */}
        <Route path="/admin/login" element={<AdminLogin />} />
        <Route
          path="/admin/dashboard"
          element={
            <ProtectedRoute>
              <AdminDashboard />
            </ProtectedRoute>
          }
        />
        <Route
          path="/admin/profile"
          element={
            <ProtectedRoute>
              <AdminProfile />
            </ProtectedRoute>
          }
        />
        {/* NEW ROUTE - Manage Admins */}
        <Route
          path="/admin/manage-admins"
          element={
            <ProtectedRoute>
              <ManageAdmins />
            </ProtectedRoute>
          }
        />
      </Routes>
    </Router>
  );
}

// Rest of the code stays the same...
// (OAuthCallback and Navbar components)

function OAuthCallback() {
  const navigate = useNavigate();

  useEffect(() => {
    const urlParams = new URLSearchParams(window.location.search);
    const token = urlParams.get('token');
    const userJson = urlParams.get('user');

    if (token && userJson) {
      try {
        const user = JSON.parse(decodeURIComponent(userJson));
        localStorage.setItem('token', token);
        localStorage.setItem('user', JSON.stringify(user));
        console.log('✅ OAuth login successful:', user.email);
        window.history.replaceState({}, document.title, '/');
        window.location.reload();
      } catch (error) {
        console.error('❌ OAuth callback error:', error);
      }
    }
  }, [navigate]);

  return null;
}

function Navbar() {
  const [user, setUser] = useState(null);
  const [admin, setAdmin] = useState(null);
  const [showDropdown, setShowDropdown] = useState(false);
  const navigate = useNavigate();

  useEffect(() => {
    const userData = localStorage.getItem('user');
    const adminData = localStorage.getItem('adminUser');

    if (userData) {
      setUser(JSON.parse(userData));
    }
    if (adminData) {
      setAdmin(JSON.parse(adminData));
    }
  }, []);

  const handleLogout = () => {
    localStorage.removeItem('token');
    localStorage.removeItem('user');
    localStorage.removeItem('adminUser');
    setUser(null);
    setAdmin(null);
    setShowDropdown(false);
    navigate('/');
    window.location.reload();
  };

  return (
    <nav style={navStyle}>
      <div style={brandStyle}>
        <Link to="/" style={brandLinkStyle}>KDMC Smart City</Link>
      </div>

      <div style={centerLinksStyle}>
        <Link to="/" style={linkStyle}>Home</Link>
        <Link to="/about" style={linkStyle}>About</Link>

        {!user && !admin && (
          <>
            <Link to="/login" style={linkStyle}>Citizen Login</Link>
            <Link to="/admin/login" style={linkStyle}>Admin</Link>
          </>
        )}

        {admin && (
          <>
            <Link to="/admin/dashboard" style={linkStyle}>Dashboard</Link>
            {admin.role === 'Super Admin' && (
              <Link to="/admin/manage-admins" style={linkStyle}>Manage Admins</Link>
            )}
          </>
        )}
      </div>

      <div style={rightSectionStyle}>
        {(user || admin) && (
          <div style={profileContainerStyle}>
            <button
              onClick={() => setShowDropdown(!showDropdown)}
              style={profileButtonStyle}
            >
              <div style={avatarStyle}>
                {user ? user.name?.charAt(0).toUpperCase() : admin?.name?.charAt(0).toUpperCase() || 'A'}
              </div>
              <span style={{ marginLeft: '8px' }}>
                {user ? user.name : admin?.name || 'Admin'}
              </span>
              <span style={{ marginLeft: '5px', fontSize: '12px' }}>▼</span>
            </button>

            {showDropdown && (
              <div style={dropdownStyle}>
                <div style={dropdownHeaderStyle}>
                  <div style={avatarLargeStyle}>
                    {user ? user.name?.charAt(0).toUpperCase() : admin?.name?.charAt(0).toUpperCase() || 'A'}
                  </div>
                  <div>
                    <div style={{ fontWeight: 'bold' }}>
                      {user ? user.name : admin?.name || 'Admin'}
                    </div>
                    <div style={{ fontSize: '12px', color: '#888' }}>
                      {user ? user.email : admin?.email || 'admin@kdmc.gov'}
                    </div>
                    <div style={{ fontSize: '11px', color: '#667eea', marginTop: '3px' }}>
                      {admin ? '👑 Admin' : '👤 Citizen'}
                    </div>
                  </div>
                </div>
                <hr style={{ margin: '10px 0', border: 'none', borderTop: '1px solid #eee' }} />
                <Link
                  to={admin ? "/admin/profile" : "/profile"}
                  style={dropdownItemStyle}
                  onClick={() => setShowDropdown(false)}
                >
                  📊 My Profile
                </Link>
                <button onClick={handleLogout} style={dropdownItemStyle}>
                  🚪 Logout
                </button>
              </div>
            )}
          </div>
        )}
      </div>
    </nav>
  );
}

const navStyle = {
  display: "flex",
  justifyContent: "space-between",
  alignItems: "center",
  padding: "15px 30px",
  background: "#111",
  position: "relative"
};

const brandStyle = {
  flex: "0 0 200px"
};

const brandLinkStyle = {
  color: "#fff",
  textDecoration: "none",
  fontWeight: "bold",
  fontSize: "18px"
};

const centerLinksStyle = {
  display: "flex",
  gap: "30px",
  alignItems: "center",
  position: "absolute",
  left: "50%",
  transform: "translateX(-50%)"
};

const rightSectionStyle = {
  flex: "0 0 200px",
  display: "flex",
  justifyContent: "flex-end"
